import { ReactComponent } from '*.src';
import ExpenseItem from './Components/ExpenseItem';

function App() {
  let item_list = [
    {
      date: "24-05-2021",
      title: "SleepWell Bed",
      amount: 12499
    },
    {
      date: "23-05-2021",
      title: "Antidandruff shampoo",
      amount: 349
    },
    {
      date: "20-05-2021",
      title: "Castor oil",
      amount: 150
    },
    {
      date: "20-05-2021",
      title: "Badam",
      amount: 750
    },
  ];
  return (
    <div className="App">
      <h2>Let's get started!</h2>
      <ExpenseItem date = {item_list[0].date} title = {item_list[0].title} price = {item_list[0].price}></ExpenseItem>
      <ExpenseItem date = {item_list[1].date} title = {item_list[1].title} price = {item_list[1].price}></ExpenseItem>
      <ExpenseItem date = {item_list[2].date} title = {item_list[2].title} price = {item_list[2].price}></ExpenseItem>
      <ExpenseItem date = {item_list[3].date} title = {item_list[3].title} price = {item_list[3].price}></ExpenseItem>
    </div>
  );
}

export default App;
